def keep_features_dicts_synced(func):
    """
    Wrapper to keep the secondary dictionary, `_column_requires_decoding`, of the `Features` class in sync with the
    main dictionary.

    This is used to avoid subclassing `UserDict`, which is slower and would break `isinstance(features, dict)`
    checks, while still supporting all the dict methods that can add, remove or replace columns (`__setitem__`,
    `__delitem__`, `update`, `pop`, `popitem`, `setdefault`, `clear`, ...).
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        self: "Features" = args[0]
        out = func(*args, **kwargs)
        assert hasattr(self, "_column_requires_decoding")
        self._column_requires_decoding = {col: require_decoding(feature) for col, feature in self.items()}
        return out

    wrapper.__doc__ = func.__doc__
    return wrapper


